@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.ExcludeFromInteractiveRouting]
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application uses cookies to improve your experience.
    We respect your privacy and handle your data responsibly.
</p>

@if (_hasConsent)
{
    <div class="alert alert-success mt-3">
        ✅ You have already accepted cookies. Thank you!
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        ⚠️ You have not yet accepted cookies.
    </div>
}

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

